    19→  painPoints?: string;
    20→  toolsUsed?: string;
    21→  timeSpent?: string;
    22→  aiAnalysis?: string;
    23→}
    24→
    25→interface SegmentData {
    26→  id?: string;
    27→  name: string;
    28→  companyType: string;
    29→  jobTitles: string[];
    30→  whyTheyCare: string;
    31→  isCustom?: boolean;
    32→}
