    34→interface SearchFilters {
    35→  location?: string;
    36→  connectionLevel?: '1st' | '2nd' | '3rd+' | 'all';
    37→  companySize?: string;
    38→}
    39→
    40→type GeneratorType = 
    41→  | 'mvp-scope' 
    42→  | 'lovable-prompt' 
    43→  | 'target-customer' 
    44→  | 'outreach-messages'
    45→  | 'customer-segments'
    46→  | 'single-segment'
    47→  | 'linkedin-search'
    48→  | 'segment-outreach'
    49→  | 'automation-analysis';
    50→
    51→type TrackType = 'startup' | 'automation';
    52→
    53→function getSystemPrompt(type: GeneratorType, track: TrackType = 'startup'): string {
    54→  if (type === 'automation-analysis') {
    55→    return `You are an expert process automation analyst. Your job is to analyze a user's workflow, identify the highest-impact automation opportunity, and recommend the BEST specific tool to build it with.
    56→
    57→Be concrete and actionable — name exact tools, explain why they fit, and describe the automation flow clearly.
    58→
    59→Tools you can recommend:
    60→- No-code automation: n8n (self-hosted, powerful integrations), Zapier (easiest, biggest app library), Make (visual, complex logic)
    61→- Frontend/UI builders: Lovable (AI app builder), v0 (UI generation)
    62→- For developers / vibe coders: Cursor (AI code editor), Claude Code (CLI coding), Antigravity, Codex
    63→
    64→Always pick ONE primary recommendation based on the user's tool stack and technical level.`;
    65→  }
    66→
    67→  if (track === 'automation' && type === 'lovable-prompt') {
    68→    return `You are an expert at writing implementation prompts for automation tools and workflow builders.
    69→Your job is to create a detailed, tool-specific prompt that can be pasted directly into the recommended tool to start building.
    70→
    71→If the user has an AI analysis from Phase 1 that recommends a specific tool, tailor the prompt for THAT tool:
    72→- For n8n: Include specific nodes, triggers, webhook configs, and data transformations
    73→- For Zapier: Include specific Zaps, triggers, actions, and filter steps
    74→- For Make: Include specific modules, scenarios, and data routing
    75→- For Lovable/v0: Include UI components, pages, and functionality
    76→- For Cursor/Claude Code: Include code architecture, APIs to integrate, and implementation steps
    77→
    78→The prompt should be immediately actionable — the user should be able to paste it and start building.`;
    79→  }
    80→
    81→  switch (type) {
    82→    case 'mvp-scope':
    83→      return `You are a startup advisor helping teams define focused MVP scopes. 
    84→Your job is to take their startup idea and distill it into ONE core feature that can be built in 90 minutes.
    85→Be specific, actionable, and ruthlessly focused. The MVP should demonstrate the core value proposition.
    86→Keep your response to 2-3 sentences maximum.`;
    87→
    88→    case 'lovable-prompt':
    89→      return `You are an expert at writing prompts for Lovable AI, a no-code app builder.
    90→Your job is to create detailed, specific prompts that Lovable can use to build working prototypes.
    91→Include specific UI components, pages, layouts, and functionality.
    92→Be clear about user flows and what the user should be able to do.
    93→Format the prompt in a clear, structured way that's easy to paste into Lovable.`;
    94→
    95→    case 'target-customer':
    96→      return `You are a customer discovery expert helping startups identify and understand their ideal customers.
    97→Your job is to create a detailed, actionable customer profile based on the startup's problem and solution.
    98→Focus on specifics that help the founder actually find and reach these people.
    99→Be concrete about demographics, behaviors, and where to find them online.`;
   100→
   101→    case 'outreach-messages':
   102→      return `You are an expert at writing cold outreach messages that get responses.
   103→Your job is to create short, personal, non-salesy messages that spark genuine conversations.
   104→The goal is to get feedback on an idea, NOT to sell anything.
   105→Messages should be under 100 words each, feel human, and have a clear but soft ask.
   106→Do NOT include any product links - the product will be shown during the conversation.`;
   107→
   108→    case 'customer-segments':
   109→      return `You are a market segmentation expert helping startups identify distinct customer groups.
   110→Your job is to identify 3-5 specific, actionable customer segments based on the startup's idea.
   111→Each segment should be distinct enough to need different messaging and outreach approaches.
   112→Focus on segments the founder can actually reach and test with.`;
   113→
   114→    case 'single-segment':
   115→      return `You are a market segmentation expert helping startups identify distinct customer groups.
   116→Your job is to identify ONE specific, actionable customer segment based on the startup's idea.
   117→The segment should be distinct and targetable with specific messaging.
   118→Focus on a segment the founder can actually reach and test with.`;
   119→
   120→    case 'linkedin-search':
   121→      return `You are an expert at creating SHORT, EFFECTIVE LinkedIn search queries.
   122→Your job is to create simple search strings that actually return results.
   123→Keep queries UNDER 50 CHARACTERS. Focus only on job titles.
   124→Do NOT use complex Boolean logic - keep it simple.
   125→Return ONLY the search query string, nothing else.`;
   126→
   127→    case 'segment-outreach':
   128→      return `You are an expert at writing personalized cold outreach messages.
   129→Your job is to create 3 DISTINCT message variants for a specific customer segment.
   130→Each message should be under 80 words, personal, and with a clear ask for a conversation.
   131→Do NOT include any product links.
   132→Format as: **Variant 1 - Problem-focused:** [message] **Variant 2 - Curiosity-driven:** [message] **Variant 3 - Direct ask:** [message]`;
   133→
   134→    default:
   135→      return 'You are a helpful startup advisor.';
   136→  }
   137→}
   138→
   139→function getUserPrompt(type: GeneratorType, data: Phase1Data, segmentData?: SegmentData, searchFilters?: SearchFilters): string {
   140→  if (type === 'automation-analysis') {
   141→    return `Analyze this workflow and recommend the best automation opportunity:
   142→
   143→**Weekly Workflow:** ${data.workflow || data.problem}
   144→**Pain Points:** ${data.painPoints || 'Not specified'}
   145→**Tools Currently Used:** ${data.toolsUsed || 'Not specified'}
   146→**Time Spent Per Week:** ${data.timeSpent || 'Not specified'}
   147→
   148→Please provide:
   149→1. **What to automate**: The specific step(s) with the highest impact to automate
   150→2. **Recommended tool**: Pick ONE primary tool (n8n, Zapier, Make, Lovable, Cursor, etc.) and explain WHY it's the best fit for this specific workflow and tool stack
   151→3. **How it works**: Describe the automation flow — trigger → actions → output
   152→4. **Alternative tools**: 1-2 alternatives if the primary doesn't fit
   153→5. **Expected time savings**: Estimate how much time this will save per week
   154→
   155→Be specific and practical. The user will use this analysis to build the automation tonight.`;
   156→  }
   157→
   158→  switch (type) {
   159→    case 'mvp-scope':
   160→      return `Based on this startup idea, define a focused MVP scope with ONE core feature that can be built in 90 minutes:
   161→
   162→**Startup Name:** ${data.name}
   163→**Problem:** ${data.problem}
   164→**Solution:** ${data.solution}
   165→**Target Customer:** ${data.customer}
   166→${data.unfairAdvantage ? `**Unfair Advantage:** ${data.unfairAdvantage}` : ''}
   167→${data.problemValidation ? `**Problem Validation:** ${data.problemValidation}` : ''}
   168→
   169→What is the single most important feature to build first? Leverage the unfair advantage if possible. Be specific and actionable.`;
   170→
   171→    case 'lovable-prompt': {
   172→      // Check if this is automation track with AI analysis
   173→      if (data.aiAnalysis && data.workflow) {
   174→        return `Create a detailed, tool-specific implementation prompt based on this automation analysis:
   175→
   176→**Workflow Being Automated:** ${data.workflow}
   177→**Pain Points:** ${data.painPoints || 'Not specified'}
   178→**Tools Involved:** ${data.toolsUsed || 'Not specified'}
   179→**Time Spent:** ${data.timeSpent || 'Not specified'}
   180→**AI Analysis & Tool Recommendation:**
   181→${data.aiAnalysis}
   182→
   183→${data.successMetrics ? `**Success Metrics:** ${data.successMetrics}` : ''}
   184→
   185→Based on the AI analysis above, generate a prompt that:
   186→1. Is tailored to the SPECIFIC tool recommended in the analysis
   187→2. Includes step-by-step setup instructions for that tool
   188→3. Specifies exact triggers, actions, and data flows
   189→4. References the actual tools from the user's stack for integrations
   190→5. Can be pasted directly into the recommended tool to start building
   191→
   192→Make the prompt immediately actionable — the user should be able to copy-paste it and start building right away.`;
   193→      }
   194→
   195→      // Default startup lovable-prompt
   196→      return `Create a detailed prompt for Lovable AI to build a prototype for this startup:
   197→
   198→**Startup Name:** ${data.name}
   199→**Problem:** ${data.problem}
   200→**Solution:** ${data.solution}
   201→**Target Customer:** ${data.customer}
   202→${data.mvpScope ? `**MVP Scope:** ${data.mvpScope}` : ''}
   203→${data.unfairAdvantage ? `**Unfair Advantage:** ${data.unfairAdvantage}` : ''}
   204→${data.successMetrics ? `**Success Metrics:** ${data.successMetrics}` : ''}
   205→
   206→Generate a complete prompt that includes:
   207→1. App overview and purpose
   208→2. Key pages/screens needed
   209→3. Specific UI components and layout
   210→4. Core functionality and user flows
   211→5. Any important design considerations
   212→6. Features that highlight the unfair advantage
   213→
   214→Format it so it can be directly pasted into Lovable.`;
   215→    }
   216→
   217→    case 'target-customer':
   218→      return `Based on this startup idea, describe the ideal target customer in detail:
   219→
   220→**Startup Name:** ${data.name}
   221→**Problem:** ${data.problem}
   222→**Solution:** ${data.solution}
   223→**Initial Customer Idea:** ${data.customer}
   224→${data.problemValidation ? `**Problem Validation:** ${data.problemValidation}` : ''}
   225→
   226→Create a detailed customer profile that includes:
   227→1. **Who they are** - Job title, company size, industry, demographics
   228→2. **Pain points** - Specific frustrations they experience daily related to this problem
   229→3. **Current solutions** - What they've tried before and why it falls short
   230→4. **Where to find them** - LinkedIn groups, communities, forums, events
   231→5. **What makes them pay attention** - Triggers that would make them interested in a solution
   232→
   233→Use the problem validation evidence to ground the profile in reality. Be specific and actionable.`;
   234→
   235→    case 'outreach-messages':
   236→      return `Create 3 different outreach message variants for reaching potential customers:
   237→
   238→**Startup Name:** ${data.name}
   239→**Problem:** ${data.problem}
   240→**Solution:** ${data.solution}
   241→**Target Customer:** ${data.targetCustomer || data.customer}
   242→${data.problemValidation ? `**Problem Validation:** ${data.problemValidation}` : ''}
   243→${data.unfairAdvantage ? `**Unfair Advantage:** ${data.unfairAdvantage}` : ''}
   244→
   245→Generate 3 distinct messages (each under 100 words):
   246→
   247→**Message 1 - Problem-focused:** Lead with the pain point and empathy. Reference validation evidence as social proof if relevant.
   248→**Message 2 - Curiosity-driven:** Tease the idea without revealing too much, spark interest
   249→**Message 3 - Direct ask:** Straightforward request for feedback/conversation
   250→
   251→Each message should:
   252→- Feel personal and human, not salesy
   253→- Include a soft ask for a quick call or chat
   254→- NOT include any product links (the product will be shown during the conversation)
   255→- Reference validation evidence when appropriate for credibility
   256→
   257→Format each message clearly separated and labeled.`;
   258→
   259→    case 'customer-segments':
   260→      return `Based on this startup and target customer, identify 3-5 distinct customer segments:
   261→
   262→**Startup Name:** ${data.name}
   263→**Problem:** ${data.problem}
   264→**Solution:** ${data.solution}
   265→**Target Customer Profile:** ${data.targetCustomer || data.customer}
   266→${data.unfairAdvantage ? `**Unfair Advantage:** ${data.unfairAdvantage}` : ''}
   267→${data.successMetrics ? `**Success Metrics (30-day goal):** ${data.successMetrics}` : ''}
   268→
   269→For each segment, provide:
   270→1. **Segment Name** - A clear, descriptive name (2-4 words)
   271→2. **Company Type** - Industry and typical company size
   272→3. **Job Titles** - 2-3 specific titles to target
   273→4. **Why They'd Care** - Specific reason this solution matters to them
   274→5. **Unique Angle** - One differentiating factor for reaching this segment
   275→
   276→Prioritize segments that align with the unfair advantage and can help achieve the success metrics.
   277→Keep segments distinct enough that each needs different messaging.
   278→Format as a numbered list with clear structure.`;
   279→
   280→    case 'single-segment':
   281→      return `Based on this startup and target customer, identify ONE distinct customer segment:
   282→
   283→**Startup Name:** ${data.name}
   284→**Problem:** ${data.problem}
   285→**Solution:** ${data.solution}
   286→**Target Customer Profile:** ${data.targetCustomer || data.customer}
   287→${data.unfairAdvantage ? `**Unfair Advantage:** ${data.unfairAdvantage}` : ''}
   288→
   289→Provide ONLY ONE segment with:
   290→1. **Segment Name** - A clear, descriptive name (2-4 words)
   291→2. **Company Type** - Industry and typical company size
   292→3. **Job Titles** - 2-3 specific titles to target
   293→4. **Why They'd Care** - Specific reason this solution matters to them
   294→
   295→Prioritize segments that align with the unfair advantage. Format as a single segment with clear labels. Make it different from common/obvious segments.`;
   296→
   297→    case 'linkedin-search':
   298→      if (!segmentData) {
   299→        return 'Create a general LinkedIn search query for startup founders: "Founder" OR "CEO"';
   300→      }
   301→      
   302→      let prompt = `Create a SHORT LinkedIn search query (UNDER 50 characters) for finding:
   303→
   304→**Job Titles:** ${segmentData.jobTitles.join(', ')}
   305→
   306→Rules:
   307→- Use ONLY job titles with OR between them
   308→- Keep it SIMPLE - example: "Product Manager" OR "PM" OR "Head of Product"
   309→- Do NOT include industry, company types, or complex Boolean logic`;
   310→
   311→      if (searchFilters?.location) {
   312→        prompt += `\n\nNote: Location filter "${searchFilters.location}" will be applied separately in LinkedIn - do NOT include it in the query.`;
   313→      }
   314→      if (searchFilters?.connectionLevel && searchFilters.connectionLevel !== 'all') {
   315→        prompt += `\nConnection level "${searchFilters.connectionLevel}" will be applied separately.`;
   316→      }
   317→      if (searchFilters?.companySize) {
   318→        prompt += `\nCompany size "${searchFilters.companySize}" will be applied separately.`;
   319→      }
   320→
   321→      prompt += `\n\nReturn ONLY the search query string, nothing else. Maximum 50 characters.`;
   322→      
   323→      return prompt;
   324→
   325→    case 'segment-outreach':
   326→      if (!segmentData) {
   327→        return 'Create 3 general outreach message variants.';
   328→      }
   329→      return `Create 3 DISTINCT outreach message variants for this customer segment:
   330→
   331→**Startup Name:** ${data.name}
   332→**Problem:** ${data.problem}
   333→**Solution:** ${data.solution}
   334→**Segment:** ${segmentData.name}
   335→**Their Role:** ${segmentData.jobTitles.join(' or ')}
   336→**Company Type:** ${segmentData.companyType}
   337→**Why They'd Care:** ${segmentData.whyTheyCare}
   338→
   339→Write 3 different messages (each under 80 words):
   340→
   341→**Variant 1 - Problem-focused:** Lead with empathy about their pain point
   342→**Variant 2 - Curiosity-driven:** Spark interest without revealing everything
   343→**Variant 3 - Direct ask:** Straightforward request for feedback
   344→
   345→Each message should:
   346→- Speak directly to their specific context
   347→- Feel personal and non-salesy
   348→- Ask for a quick conversation
   349→- NOT include any product links
   350→
   351→Format exactly as:
   352→**Variant 1 - Problem-focused:**
   353→[message]
   354→
   355→**Variant 2 - Curiosity-driven:**
   356→[message]
   357→
   358→**Variant 3 - Direct ask:**
   359→[message]`;
   360→
   361→    default:
   362→      return 'Help with startup advice.';
   363→  }
   364→}
   365→
   366→// In-memory rate limiter: 20 requests per hour per auth token
   367→const RATE_LIMIT_MAX = 20;
   368→const RATE_LIMIT_WINDOW_MS = 60 * 60 * 1000; // 1 hour
   369→
   370→interface RateLimitEntry {
   371→  count: number;
   372→  windowStart: number;
   373→}
   374→
   375→const rateLimitMap = new Map<string, RateLimitEntry>();
   376→
   377→function checkRateLimit(token: string): { allowed: boolean; retryAfterSec?: number } {
   378→  const now = Date.now();
   379→  const entry = rateLimitMap.get(token);
   380→
   381→  if (!entry || now - entry.windowStart > RATE_LIMIT_WINDOW_MS) {
   382→    rateLimitMap.set(token, { count: 1, windowStart: now });
   383→    return { allowed: true };
   384→  }
   385→
   386→  if (entry.count >= RATE_LIMIT_MAX) {
   387→    const retryAfterSec = Math.ceil((entry.windowStart + RATE_LIMIT_WINDOW_MS - now) / 1000);
   388→    return { allowed: false, retryAfterSec };
   389→  }
   390→
   391→  entry.count++;
   392→  return { allowed: true };
   393→}
   394→
   395→serve(async (req) => {
   396→  if (req.method === "OPTIONS") {
   397→    return new Response(null, { headers: corsHeaders });
   398→  }
   399→
   400→  try {
   401→    const { type, phase1Data, segmentData, searchFilters, track } = await req.json() as {
   402→      type: GeneratorType;
   403→      phase1Data: Phase1Data;
   404→      segmentData?: SegmentData;
   405→      searchFilters?: SearchFilters;
   406→      track?: TrackType;
   407→    };
   408→
   409→    // Rate limit by authorization token
   410→    const authToken = req.headers.get("authorization") || "anonymous";
   411→    const rateCheck = checkRateLimit(authToken);
   412→    if (!rateCheck.allowed) {
   413→      return new Response(
   414→        JSON.stringify({
   415→          error: `You've used all ${RATE_LIMIT_MAX} AI generations this hour. Try again in ${Math.ceil((rateCheck.retryAfterSec || 60) / 60)} minutes.`,
   416→        }),
   417→        { status: 429, headers: { ...corsHeaders, "Content-Type": "application/json" } }
   418→      );
   419→    }
   420→
   421→    if (!type || !phase1Data) {
   422→      return new Response(
   423→        JSON.stringify({ error: "Missing required fields: type and phase1Data" }),
   424→        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
   425→      );
   426→    }
   427→
   428→    const LOVABLE_API_KEY = Deno.env.get("LOVABLE_API_KEY");
   429→    if (!LOVABLE_API_KEY) {
   430→      console.error("LOVABLE_API_KEY is not configured");
   431→      return new Response(
   432→        JSON.stringify({ error: "AI service not configured" }),
   433→        { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
   434→      );
   435→    }
   436→
   437→    const response = await fetch("https://ai.gateway.lovable.dev/v1/chat/completions", {
   438→      method: "POST",
   439→      headers: {
   440→        Authorization: `Bearer ${LOVABLE_API_KEY}`,
   441→        "Content-Type": "application/json",
   442→      },
   443→      body: JSON.stringify({
   444→        model: "google/gemini-3-flash-preview",
   445→        messages: [
   446→          { role: "system", content: getSystemPrompt(type, track || 'startup') },
   447→          { role: "user", content: getUserPrompt(type, phase1Data, segmentData, searchFilters) },
   448→        ],
   449→      }),
   450→    });
   451→
   452→    if (!response.ok) {
   453→      if (response.status === 429) {
   454→        return new Response(
   455→          JSON.stringify({ error: "Rate limit exceeded. Please try again in a moment." }),
   456→          { status: 429, headers: { ...corsHeaders, "Content-Type": "application/json" } }
   457→        );
   458→      }
   459→      if (response.status === 402) {
   460→        return new Response(
   461→          JSON.stringify({ error: "AI credits exhausted. Please add credits to continue." }),
   462→          { status: 402, headers: { ...corsHeaders, "Content-Type": "application/json" } }
   463→        );
   464→      }
   465→      const errorText = await response.text();
   466→      console.error("AI gateway error:", response.status, errorText);
   467→      return new Response(
   468→        JSON.stringify({ error: "Failed to generate content" }),
   469→        { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
   470→      );
   471→    }
   472→
   473→    const result = await response.json();
   474→    const content = result.choices?.[0]?.message?.content;
   475→
   476→    if (!content) {
   477→      return new Response(
   478→        JSON.stringify({ error: "No content generated" }),
   479→        { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
   480→      );
   481→    }
   482→
   483→    return new Response(
   484→      JSON.stringify({ content }),
   485→      { headers: { ...corsHeaders, "Content-Type": "application/json" } }
   486→    );
   487→  } catch (error) {
   488→    console.error("generate-startup-content error:", error);
   489→    return new Response(
   490→      JSON.stringify({ error: error instanceof Error ? error.message : "Unknown error" }),
   491→      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
   492→    );
   493→  }
   494→});
