-- =============================================================================
-- SECTION 9: RLS POLICIES - profiles
-- =============================================================================

CREATE POLICY "Users can view all profiles" ON public.profiles
    FOR SELECT TO authenticated USING (true);

CREATE POLICY "Users can insert own profile" ON public.profiles
    FOR INSERT TO authenticated WITH CHECK ((auth.uid() = user_id));

CREATE POLICY "Users can update own profile" ON public.profiles
    FOR UPDATE TO authenticated USING ((auth.uid() = user_id));

-- =============================================================================
-- SECTION 10: RLS POLICIES - user_roles
-- =============================================================================

CREATE POLICY "Admins can manage roles" ON public.user_roles
    TO authenticated USING (public.has_role(auth.uid(), 'admin'::public.app_role));

CREATE POLICY "Users can view own roles" ON public.user_roles
    FOR SELECT TO authenticated USING ((auth.uid() = user_id));

-- =============================================================================
-- SECTION 11: RLS POLICIES - events
-- =============================================================================

CREATE POLICY "Admins can manage events" ON public.events
    TO authenticated USING (public.has_role(auth.uid(), 'admin'::public.app_role));

CREATE POLICY "Creators can manage own events" ON public.events
    TO authenticated USING ((created_by = auth.uid()));

CREATE POLICY "Anyone can view scheduled events" ON public.events
    FOR SELECT TO authenticated
    USING (((status <> 'draft'::public.event_status) OR (created_by = auth.uid())));

-- =============================================================================
-- SECTION 12: RLS POLICIES - event_registrations
-- =============================================================================

CREATE POLICY "Admins can view all registrations" ON public.event_registrations
    FOR SELECT TO authenticated USING (public.has_role(auth.uid(), 'admin'::public.app_role));

CREATE POLICY "Users can register for events" ON public.event_registrations
    FOR INSERT TO authenticated WITH CHECK ((auth.uid() = user_id));

CREATE POLICY "Users can unregister" ON public.event_registrations
    FOR DELETE TO authenticated USING ((auth.uid() = user_id));

CREATE POLICY "Users can view own registrations" ON public.event_registrations
    FOR SELECT TO authenticated USING ((auth.uid() = user_id));

-- =============================================================================
-- SECTION 13: RLS POLICIES - teams
-- =============================================================================

CREATE POLICY "Anyone can view teams" ON public.teams
    FOR SELECT USING (true);

CREATE POLICY "Event participants can view teams" ON public.teams
    FOR SELECT TO authenticated USING (true);

CREATE POLICY "Admins can view all teams" ON public.teams
    FOR SELECT TO authenticated
    USING (public.has_role(auth.uid(), 'admin'));

CREATE POLICY "Anyone can create teams" ON public.teams
    FOR INSERT WITH CHECK (true);

CREATE POLICY "Authenticated users can create teams" ON public.teams
    FOR INSERT TO authenticated WITH CHECK ((auth.uid() = created_by));

CREATE POLICY "Anyone can update teams" ON public.teams
    FOR UPDATE USING (true);

CREATE POLICY "Team creators can update teams" ON public.teams
    FOR UPDATE TO authenticated USING ((created_by = auth.uid()));

CREATE POLICY "Admins can update all teams" ON public.teams
    FOR UPDATE USING (has_role(auth.uid(), 'admin'::app_role));

CREATE POLICY "Admins can delete all teams" ON public.teams
    FOR DELETE USING (has_role(auth.uid(), 'admin'::app_role));

-- =============================================================================
-- SECTION 14: RLS POLICIES - team_members
-- =============================================================================

CREATE POLICY "Team members can view members" ON public.team_members
    FOR SELECT TO authenticated
    USING ((public.is_team_member(auth.uid(), team_id) OR (auth.uid() = user_id)));

CREATE POLICY "Users can join teams" ON public.team_members
    FOR INSERT TO authenticated WITH CHECK ((auth.uid() = user_id));

CREATE POLICY "Users can leave teams" ON public.team_members
    FOR DELETE TO authenticated USING ((auth.uid() = user_id));

-- =============================================================================
-- SECTION 15: RLS POLICIES - team_member_names
-- =============================================================================

CREATE POLICY "Anyone can view team member names" ON public.team_member_names
    FOR SELECT USING (true);

CREATE POLICY "Anyone can insert team member names" ON public.team_member_names
    FOR INSERT WITH CHECK (true);

-- =============================================================================
-- SECTION 16: RLS POLICIES - task_progress
-- =============================================================================

CREATE POLICY "Anyone can view task progress" ON public.task_progress
    FOR SELECT USING (true);

CREATE POLICY "Anyone can insert task progress" ON public.task_progress
    FOR INSERT WITH CHECK (true);

CREATE POLICY "Anyone can update task progress" ON public.task_progress
    FOR UPDATE USING (true);

CREATE POLICY "Anyone can delete task progress" ON public.task_progress
    FOR DELETE USING (true);

CREATE POLICY "Team members can view progress" ON public.task_progress
    FOR SELECT TO authenticated USING (public.is_team_member(auth.uid(), team_id));

CREATE POLICY "Team members can update progress" ON public.task_progress
    FOR INSERT TO authenticated WITH CHECK (public.is_team_member(auth.uid(), team_id));

CREATE POLICY "Team members can modify progress" ON public.task_progress
    FOR UPDATE TO authenticated USING (public.is_team_member(auth.uid(), team_id));

CREATE POLICY "Admins can view all task progress" ON public.task_progress
    FOR SELECT TO authenticated
    USING (public.has_role(auth.uid(), 'admin'));

CREATE POLICY "Admins can delete all task progress" ON public.task_progress
    FOR DELETE USING (has_role(auth.uid(), 'admin'::app_role));

-- =============================================================================
-- SECTION 17: RLS POLICIES - team_deliverables
-- =============================================================================

CREATE POLICY "Team members can view deliverables" ON public.team_deliverables
    FOR SELECT TO authenticated USING (public.is_team_member(auth.uid(), team_id));

CREATE POLICY "Team members can add deliverables" ON public.team_deliverables
    FOR INSERT TO authenticated WITH CHECK (public.is_team_member(auth.uid(), team_id));

CREATE POLICY "Team members can update deliverables" ON public.team_deliverables
    FOR UPDATE TO authenticated USING (public.is_team_member(auth.uid(), team_id));

-- =============================================================================
-- SECTION 18: RLS POLICIES - customer_segments
-- =============================================================================

CREATE POLICY "Team members can view their team segments" ON public.customer_segments
    FOR SELECT USING (((EXISTS ( SELECT 1
       FROM public.team_members
      WHERE ((team_members.team_id = customer_segments.team_id) AND (team_members.user_id = auth.uid())))) OR (EXISTS ( SELECT 1
       FROM public.teams
      WHERE (teams.id = customer_segments.team_id)))));

CREATE POLICY "Team members can insert segments for their team" ON public.customer_segments
    FOR INSERT WITH CHECK (((EXISTS ( SELECT 1
       FROM public.team_members
      WHERE ((team_members.team_id = customer_segments.team_id) AND (team_members.user_id = auth.uid())))) OR true));

CREATE POLICY "Team members can update their team segments" ON public.customer_segments
    FOR UPDATE USING (((EXISTS ( SELECT 1
       FROM public.team_members
      WHERE ((team_members.team_id = customer_segments.team_id) AND (team_members.user_id = auth.uid())))) OR true));

CREATE POLICY "Team members can delete their team segments" ON public.customer_segments
    FOR DELETE USING (((EXISTS ( SELECT 1
       FROM public.team_members
      WHERE ((team_members.team_id = customer_segments.team_id) AND (team_members.user_id = auth.uid())))) OR true));

-- =============================================================================
-- SECTION 19: RLS POLICIES - sprint_timer
-- =============================================================================

CREATE POLICY "Everyone can view timer" ON public.sprint_timer
    FOR SELECT USING (true);

CREATE POLICY "Admins can update timer" ON public.sprint_timer
    FOR UPDATE USING (
      EXISTS (
        SELECT 1 FROM public.user_roles
        WHERE user_roles.user_id = auth.uid()
        AND user_roles.role = 'admin'
      )
    );

CREATE POLICY "Admins can insert timer" ON public.sprint_timer
    FOR INSERT WITH CHECK (
      EXISTS (
        SELECT 1 FROM public.user_roles
        WHERE user_roles.user_id = auth.uid()
        AND user_roles.role = 'admin'
      )
    );

